import { useEffect, useMemo, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { deleteVehicle, getVehicles } from "../../api/vehicleApi";
import { getAuth } from "../../utils/auth";

export default function VehicleList() {
  const [vehicles, setVehicles] = useState([]);
  const [typeFilter, setTypeFilter] = useState("all");
  const [loading, setLoading] = useState(false);
  const [imageIndices, setImageIndices] = useState({}); // Track current image index for each vehicle

  const navigate = useNavigate();

  const auth = getAuth();
  const role = auth?.role;
  const canManageVehicles = role === "admin" || role === "manager";

  const load = async () => {
    setLoading(true);
    try {
      const res = await getVehicles();
      setVehicles(res.data || []);
    } catch (err) {
      alert(err.response?.data?.message || "Failed to load vehicles");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, []);

  const vehicleTypes = useMemo(() => {
    const s = new Set(vehicles.map((v) => v.type).filter(Boolean));
    return ["all", ...Array.from(s)];
  }, [vehicles]);

  const filtered = useMemo(() => {
    if (typeFilter === "all") return vehicles;
    return vehicles.filter((v) => v.type === typeFilter);
  }, [vehicles, typeFilter]);

  const stats = useMemo(() => {
    const total = vehicles.length;
    const available = vehicles.filter((v) => v.status === "available").length;
    const reserved = vehicles.filter((v) => v.status === "reserved").length;
    const sold = vehicles.filter((v) => v.status === "sold").length;
    const totalValue = vehicles.reduce((sum, v) => sum + Number(v.price || 0), 0);

    return { total, available, reserved, sold, totalValue };
  }, [vehicles]);

  const bookNow = (vehicleId, status) => {
    if (status !== "available") return alert("This vehicle is not available for booking.");
    if (!localStorage.getItem("token")) {
      alert("Please login to book an appointment.");
      return navigate("/login");
    }
    navigate("/book-appointment", { state: { vehicleId } });
  };

  const onDelete = async (id) => {
    if (!canManageVehicles) return alert("Access denied");
    if (!window.confirm("Delete this vehicle permanently?")) return;

    try {
      await deleteVehicle(id);
      setVehicles((prev) => prev.filter((v) => v._id !== id));
      alert("Vehicle deleted");
    } catch (err) {
      alert(err.response?.data?.message || "Delete failed");
    }
  };

  const badgeClass = (status) => {
    if (status === "available") return "badge badgeOk";
    if (status === "reserved") return "badge badgeWarn";
    if (status === "sold") return "badge badgeBad";
    return "badge";
  };

  const getCover = (v) => {
    const imageUrl = v?.images?.[0]?.url;
    if (!imageUrl) return "";
    // Convert relative URL to full backend URL
    return imageUrl.startsWith("http") ? imageUrl : `http://localhost:8070${imageUrl}`;
  };

  // Premium KPI Card Component
  const KPICard = ({ label, value, subtext }) => (
    <div style={{
      backgroundColor: "var(--bg-card)",
      borderRadius: "12px",
      border: "1px solid var(--border)",
      padding: "24px",
      position: "relative",
      overflow: "hidden",
      transition: "all 0.3s cubic-bezier(0.4, 0, 0.2, 1)",
      boxShadow: "0 4px 12px rgba(0,0,0,0.05)",
      cursor: "default"
    }}
    onMouseEnter={(e) => {
      e.currentTarget.style.transform = "translateY(-6px)";
      e.currentTarget.style.boxShadow = "0 12px 24px rgba(76, 175, 80, 0.15)";
      e.currentTarget.style.borderColor = "var(--primary)";
    }}
    onMouseLeave={(e) => {
      e.currentTarget.style.transform = "translateY(0)";
      e.currentTarget.style.boxShadow = "0 4px 12px rgba(0,0,0,0.05)";
      e.currentTarget.style.borderColor = "var(--border)";
    }}>
      {/* Decorative Gradient Background */}
      <div style={{
        position: "absolute",
        top: "-50%",
        right: "-50%",
        width: "200px",
        height: "200px",
        background: "linear-gradient(135deg, var(--primary-soft) 0%, transparent 70%)",
        borderRadius: "50%",
        opacity: 0.5,
        pointerEvents: "none"
      }} />

      <div style={{ position: "relative", zIndex: 1 }}>
        <div style={{
          fontSize: "13px",
          fontWeight: 600,
          color: "var(--text-muted)",
          letterSpacing: "0.4px",
          textTransform: "uppercase",
          marginBottom: "8px"
        }}>
          {label}
        </div>
        <div style={{
          fontSize: "32px",
          fontWeight: 800,
          color: "var(--text)",
          margin: "0 0 8px 0",
          letterSpacing: "-0.5px"
        }}>
          {value}
        </div>
        <div style={{
          fontSize: "13px",
          color: "var(--text-muted)",
          fontWeight: 300
        }}>
          {subtext}
        </div>
      </div>
    </div>
  );

  // Premium Vehicle Card Component
  const VehicleCardLuxury = ({ vehicle: v, canManage, onBook, onEdit, onDelete, onViewDetails }) => {
    const cover = getCover(v);
    const currentImageIndex = imageIndices[v._id] || 0;

    return (
      <div style={{
        backgroundColor: "var(--bg-card)",
        borderRadius: "12px",
        border: "1px solid var(--border)",
        overflow: "hidden",
        display: "flex",
        flexDirection: "column",
        transition: "all 0.3s cubic-bezier(0.4, 0, 0.2, 1)",
        boxShadow: "0 4px 16px rgba(0,0,0,0.08)",
        cursor: "pointer"
      }}
      onMouseEnter={(e) => {
        e.currentTarget.style.transform = "translateY(-8px)";
        e.currentTarget.style.boxShadow = "0 16px 32px rgba(76, 175, 80, 0.14)";
        e.currentTarget.style.borderColor = "var(--primary)";
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.transform = "translateY(0)";
        e.currentTarget.style.boxShadow = "0 4px 16px rgba(0,0,0,0.08)";
        e.currentTarget.style.borderColor = "var(--border)";
      }}>
        {/* Image Carousel Container */}
        <div style={{
          position: "relative",
          height: "240px",
          backgroundColor: "var(--bg)",
          overflow: "hidden",
          borderBottom: "1px solid var(--border)"
        }}>
          {cover ? (
            <img 
              src={cover} 
              alt={v.brand}
              style={{
                width: "100%",
                height: "100%",
                objectFit: "cover",
                transition: "transform 0.3s"
              }}
            />
          ) : (
            <div style={{
              width: "100%",
              height: "100%",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              color: "var(--text-muted)",
              fontSize: "13px",
              fontWeight: 500
            }}>
              No Image Available
            </div>
          )}

          {/* Status Badge */}
          <div style={{
            position: "absolute",
            top: "12px",
            right: "12px",
            padding: "6px 12px",
            borderRadius: "6px",
            fontSize: "12px",
            fontWeight: 700,
            letterSpacing: "0.3px",
            textTransform: "uppercase",
            backgroundColor: 
              v.status === "available" ? "#d4edda" :
              v.status === "reserved" ? "#fff3cd" :
              "#f8d7da",
            color: 
              v.status === "available" ? "#155724" :
              v.status === "reserved" ? "#856404" :
              "#721c24",
            boxShadow: "0 2px 8px rgba(0,0,0,0.1)"
          }}>
            {v.status}
          </div>
        </div>

        {/* Card Content */}
        <div style={{
          flex: 1,
          display: "flex",
          flexDirection: "column",
          padding: "16px"
        }}>
          {/* Title & Meta */}
          <div style={{ marginBottom: "12px" }}>
            <div style={{
              fontSize: "16px",
              fontWeight: 700,
              color: "var(--text)",
              lineHeight: "1.3",
              marginBottom: "4px",
              letterSpacing: "-0.3px"
            }}>
              {v.brand}
            </div>
            <div style={{
              fontSize: "13px",
              color: "var(--text-muted)",
              lineHeight: "1.4",
              fontWeight: 300
            }}>
              {v.type} • {v.year}
            </div>
          </div>

          {/* Price */}
          <div style={{
            fontSize: "16px",
            fontWeight: 700,
            color: "var(--primary)",
            marginBottom: "12px",
            letterSpacing: "-0.2px"
          }}>
            LKR {Number(v.price || 0).toLocaleString()}
          </div>

          {/* Spacer */}
          <div style={{ flex: 1 }} />

          {/* Action Buttons */}
          <div style={{
            display: "grid",
            gridTemplateColumns: canManage ? "1fr 1fr 40px" : "1fr",
            gap: "8px"
          }}>
            <button
              onClick={(e) => {
                e.stopPropagation();
                onBook();
              }}
              disabled={v.status !== "available"}
              style={{
                padding: "10px 12px",
                fontSize: "13px",
                fontWeight: 700,
                backgroundColor: v.status === "available" ? "var(--primary)" : "#ccc",
                color: "white",
                border: "none",
                borderRadius: "8px",
                cursor: v.status === "available" ? "pointer" : "not-allowed",
                transition: "all 0.2s",
                letterSpacing: "0.2px"
              }}
              onMouseEnter={(e) => v.status === "available" && (e.currentTarget.style.boxShadow = "0 4px 12px rgba(76, 175, 80, 0.3)")}
              onMouseLeave={(e) => (e.currentTarget.style.boxShadow = "none")}
            >
              Book Now
            </button>

            {canManage && (
              <>
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    onEdit();
                  }}
                  style={{
                    padding: "10px 12px",
                    fontSize: "13px",
                    fontWeight: 600,
                    backgroundColor: "var(--bg)",
                    color: "var(--text)",
                    border: "1px solid var(--border)",
                    borderRadius: "8px",
                    cursor: "pointer",
                    transition: "all 0.2s"
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.backgroundColor = "var(--primary-soft)";
                    e.currentTarget.style.borderColor = "var(--primary)";
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.backgroundColor = "var(--bg)";
                    e.currentTarget.style.borderColor = "var(--border)";
                  }}
                >
                  Edit
                </button>

                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    onDelete();
                  }}
                  style={{
                    padding: "10px 8px",
                    fontSize: "13px",
                    fontWeight: 600,
                    backgroundColor: "#fee",
                    color: "#c33",
                    border: "1px solid #fcc",
                    borderRadius: "8px",
                    cursor: "pointer",
                    transition: "all 0.2s"
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.backgroundColor = "#fdd";
                    e.currentTarget.style.borderColor = "#c33";
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.backgroundColor = "#fee";
                    e.currentTarget.style.borderColor = "#fcc";
                  }}
                >
                  ✕
                </button>
              </>
            )}
          </div>
        </div>
      </div>
    );
  };

  return (
    <div style={{ backgroundColor: "var(--bg)", paddingBottom: "40px" }}>
      {/* Page Header */}
      <div style={{
        paddingBottom: "40px",
        borderBottom: "1px solid var(--border)",
        marginBottom: "40px"
      }}>
        <h1 style={{
          fontSize: "32px",
          fontWeight: 800,
          color: "var(--text)",
          margin: "0 0 8px 0",
          letterSpacing: "-0.5px"
        }}>
          Vehicle Inventory
        </h1>
        <p style={{
          fontSize: "15px",
          color: "var(--text-muted)",
          margin: 0,
          fontWeight: 300
        }}>
          Explore and manage your complete vehicle collection
        </p>
      </div>

      {/* KPI Cards */}
      <div style={{
        display: "grid",
        gridTemplateColumns: "repeat(auto-fit, minmax(260px, 1fr))",
        gap: 20,
        marginBottom: 48,
        maxWidth: "1400px",
        margin: "0 auto 48px auto",
        padding: "0 20px"
      }}>
        <KPICard label="Total Vehicles" value={loading ? "—" : stats.total} subtext="All inventory items" />
        <KPICard label="Available" value={loading ? "—" : stats.available} subtext="Ready for booking" />
        <KPICard label="Reserved" value={loading ? "—" : stats.reserved} subtext="Pending transactions" />
        <KPICard label="Total Value" value={loading ? "—" : `LKR ${Math.round(stats.totalValue / 1000)}K`} subtext="Combined inventory" />
      </div>

      {/* Filter & Actions Card */}
      <div style={{
        maxWidth: "1400px",
        margin: "0 auto 40px auto",
        padding: "0 20px"
      }}>
        <div style={{
          backgroundColor: "var(--bg-card)",
          borderRadius: "12px",
          border: "1px solid var(--border)",
          padding: "24px",
          boxShadow: "0 4px 12px rgba(0,0,0,0.05)"
        }}>
          <div style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            gap: 24,
            flexWrap: "wrap"
          }}>
            <div>
              <h3 style={{
                fontSize: "16px",
                fontWeight: 700,
                color: "var(--text)",
                margin: "0 0 4px 0",
                letterSpacing: "-0.3px"
              }}>
                Filter Inventory
              </h3>
              <p style={{
                fontSize: "13px",
                color: "var(--text-muted)",
                margin: 0,
                fontWeight: 300
              }}>
                Browse vehicles by type or manage your collection
              </p>
            </div>

            <div style={{ display: "flex", gap: 12, alignItems: "center", flexWrap: "wrap" }}>
              <select
                value={typeFilter}
                onChange={(e) => setTypeFilter(e.target.value)}
                style={{
                  padding: "10px 14px",
                  fontSize: "14px",
                  fontWeight: 600,
                  border: "1px solid var(--border)",
                  borderRadius: "8px",
                  backgroundColor: "var(--bg)",
                  color: "var(--text)",
                  cursor: "pointer",
                  minWidth: 200,
                  transition: "all 0.2s",
                  outline: "none"
                }}
                onFocus={(e) => {
                  e.currentTarget.style.borderColor = "var(--primary)";
                  e.currentTarget.style.boxShadow = "0 0 0 3px var(--primary-soft)";
                }}
                onBlur={(e) => {
                  e.currentTarget.style.borderColor = "var(--border)";
                  e.currentTarget.style.boxShadow = "none";
                }}
              >
                {vehicleTypes.map((t) => (
                  <option key={t} value={t}>
                    {t === "all" ? "All Types" : t}
                  </option>
                ))}
              </select>

              <button 
                onClick={load} 
                disabled={loading}
                style={{
                  padding: "10px 16px",
                  fontSize: "13px",
                  fontWeight: 600,
                  border: "1px solid var(--border)",
                  backgroundColor: "var(--bg)",
                  color: "var(--text)",
                  borderRadius: "8px",
                  cursor: loading ? "not-allowed" : "pointer",
                  transition: "all 0.2s",
                  opacity: loading ? 0.6 : 1
                }}
                onMouseEnter={(e) => !loading && (e.currentTarget.style.backgroundColor = "var(--bg-hover)")}
                onMouseLeave={(e) => !loading && (e.currentTarget.style.backgroundColor = "var(--bg)")}
              >
                {loading ? "Loading..." : "↻ Refresh"}
              </button>

              {canManageVehicles && (
                <button
                  onClick={() => navigate("/vehicles/add")}
                  style={{
                    padding: "10px 16px",
                    fontSize: "13px",
                    fontWeight: 700,
                    backgroundColor: "var(--primary)",
                    color: "white",
                    border: "none",
                    borderRadius: "8px",
                    cursor: "pointer",
                    transition: "all 0.2s",
                    letterSpacing: "0.3px"
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.backgroundColor = "var(--primary-hover)";
                    e.currentTarget.style.transform = "translateY(-2px)";
                    e.currentTarget.style.boxShadow = "0 6px 16px rgba(76, 175, 80, 0.3)";
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.backgroundColor = "var(--primary)";
                    e.currentTarget.style.transform = "translateY(0)";
                    e.currentTarget.style.boxShadow = "none";
                  }}
                >
                  + Add Vehicle
                </button>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Vehicle Grid */}
      <div style={{ maxWidth: "1400px", margin: "0 auto", padding: "0 20px" }}>
        {loading ? (
          <div style={{ textAlign: "center", padding: "80px 20px", color: "var(--text-muted)" }}>
            <div style={{ fontSize: "16px", fontWeight: 500 }}>Loading vehicles...</div>
          </div>
        ) : filtered.length === 0 ? (
          <div style={{ textAlign: "center", padding: "80px 20px", color: "var(--text-muted)" }}>
            <div style={{ fontSize: "16px", fontWeight: 500 }}>No vehicles found for the selected type</div>
          </div>
        ) : (
          <div style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fill, minmax(320px, 1fr))",
            gap: 24
          }}>
            {filtered.map((v) => (
              <VehicleCardLuxury 
                key={v._id} 
                vehicle={v} 
                canManage={canManageVehicles}
                onBook={() => bookNow(v._id, v.status)}
                onEdit={() => navigate(`/vehicles/edit/${v._id}`)}
                onDelete={() => onDelete(v._id)}
                onViewDetails={() => navigate(`/vehicles/${v._id}`)}
              />
            ))}
          </div>
        )}
      </div>

      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @media (max-width: 768px) {
          div[style*="gridTemplateColumns: repeat(auto-fill"] {
            grid-template-columns: 1fr !important;
          }
          div[style*="gridTemplateColumns: repeat(auto-fit"] {
            grid-template-columns: 1fr !important;
          }
        }
      `}</style>
    </div>
  );
}

// Image Carousel Component
function ImageCarousel({ vehicle, isCompact = false, onIndexChange }) {
  const [currentIndex, setCurrentIndex] = useState(0);

  // Get formatted image URLs
  const images = useMemo(() => {
    return (vehicle?.images || []).map((img) => ({
      url: img.url.startsWith("http") ? img.url : `http://localhost:8070${img.url}`,
      filename: img.filename,
    }));
  }, [vehicle]);

  const currentImage = images.length > 0 ? images[currentIndex] : null;

  // Auto-play carousel
  useEffect(() => {
    if (images.length <= 1) return;

    const interval = setInterval(() => {
      setCurrentIndex((prev) => (prev + 1) % images.length);
    }, 4000); // Change image every 4 seconds

    return () => clearInterval(interval);
  }, [images.length]);

  const goToPrevious = () => {
    const newIndex = currentIndex === 0 ? images.length - 1 : currentIndex - 1;
    setCurrentIndex(newIndex);
    onIndexChange(newIndex);
  };

  const goToNext = () => {
    const newIndex = (currentIndex + 1) % images.length;
    setCurrentIndex(newIndex);
    onIndexChange(newIndex);
  };

  const aspectRatio = isCompact ? "16 / 10" : "4 / 3";
  const buttonSize = isCompact ? 28 : 36;
  const buttonFontSize = isCompact ? "16px" : "18px";

  if (images.length === 0) {
    return (
      <div style={{ width: "100%", aspectRatio, background: "#f3f4f6", display: "grid", placeItems: "center", color: "#6b7280", fontSize: "12px", fontWeight: "600" }}>
        No Photos
      </div>
    );
  }

  return (
    <div style={{ position: "relative", width: "100%", aspectRatio, background: "#f3f4f6", overflow: "hidden", display: "flex", alignItems: "center", justifyContent: "center" }}>
      {/* Main Image */}
      {currentImage && (
        <img
          src={currentImage.url}
          alt={`${vehicle.brand} ${currentIndex + 1}`}
          style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }}
        />
      )}

      {/* Previous Button */}
      {images.length > 1 && (
        <button
          onClick={goToPrevious}
          style={{
            position: "absolute",
            left: 6,
            top: "50%",
            transform: "translateY(-50%)",
            background: "rgba(0, 0, 0, 0.5)",
            color: "white",
            border: "none",
            width: buttonSize,
            height: buttonSize,
            borderRadius: 3,
            cursor: "pointer",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: buttonFontSize,
            fontWeight: "bold",
            transition: "background 0.2s",
            zIndex: 10,
          }}
          onMouseEnter={(e) => e.target.style.background = "rgba(0, 0, 0, 0.8)"}
          onMouseLeave={(e) => e.target.style.background = "rgba(0, 0, 0, 0.5)"}
        >
          ‹
        </button>
      )}

      {/* Next Button */}
      {images.length > 1 && (
        <button
          onClick={goToNext}
          style={{
            position: "absolute",
            right: 6,
            top: "50%",
            transform: "translateY(-50%)",
            background: "rgba(0, 0, 0, 0.5)",
            color: "white",
            border: "none",
            width: buttonSize,
            height: buttonSize,
            borderRadius: 3,
            cursor: "pointer",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: buttonFontSize,
            fontWeight: "bold",
            transition: "background 0.2s",
            zIndex: 10,
          }}
          onMouseEnter={(e) => e.target.style.background = "rgba(0, 0, 0, 0.8)"}
          onMouseLeave={(e) => e.target.style.background = "rgba(0, 0, 0, 0.5)"}
        >
          ›
        </button>
      )}

      {/* Image Counter */}
      {images.length > 1 && (
        <div
          style={{
            position: "absolute",
            bottom: 6,
            right: 6,
            background: "rgba(0, 0, 0, 0.6)",
            color: "white",
            padding: "3px 6px",
            borderRadius: 3,
            fontSize: "11px",
            fontWeight: "600",
            zIndex: 10,
          }}
        >
          {currentIndex + 1} / {images.length}
        </div>
      )}

      {/* Image Indicators (Dots) */}
      {images.length > 1 && (
        <div
          style={{
            position: "absolute",
            bottom: 6,
            left: "50%",
            transform: "translateX(-50%)",
            display: "flex",
            gap: 6,
            zIndex: 10,
          }}
        >
          {images.map((_, idx) => (
            <button
              key={idx}
              onClick={() => {
                setCurrentIndex(idx);
                onIndexChange(idx);
              }}
              style={{
                width: 6,
                height: 6,
                borderRadius: "50%",
                background: idx === currentIndex ? "white" : "rgba(255, 255, 255, 0.5)",
                border: "none",
                cursor: "pointer",
                transition: "background 0.2s",
              }}
              title={`Go to image ${idx + 1}`}
            />
          ))}
        </div>
      )}
    </div>
  );
}

